const fs   = require('fs');
const path = require('path');

const params  = $('Set Global Parameters').first().json;
const deckRaw = $input.first().json;
const deck    = deckRaw.data || deckRaw;

const deckDir = deck.Assets.Directory.replace(/\\/g, '/');

const jobs = [];
let skipped = 0;
let noSource = 0;

for (const cardRef of deck.Cards || []) {
  const cardJsonPath = path.join(deckDir, cardRef.File).replace(/\\/g, '/');
  if (!fs.existsSync(cardJsonPath)) {
    console.warn('[Build Rotation Job List] Missing card JSON: ' + cardJsonPath);
    continue;
  }

  const cardData = JSON.parse(fs.readFileSync(cardJsonPath, 'utf8'));
  const meta     = cardData['data.Cards'];
  if (!meta) continue;

  const cardName = meta.Card;
  const cardDir  = ((meta.Directory) || path.join(deckDir, 'Cards')).replace(/\\/g, '/');

  // Find the "between" orientation record
  const betweenRec = (meta.records || []).find(function(r) {
    return r.Orientation === 'between';
  });

  if (!betweenRec) {
    console.warn('[Build Rotation Job List] No between record for: ' + cardName);
    continue;
  }

  const assets = betweenRec.Assets;
  if (!assets) {
    console.warn('[Build Rotation Job List] No Assets in between record for: ' + cardName);
    continue;
  }

  const sourceFilename = assets.CardImage;
  const outputFilename = assets.CardImageUpright;

  if (!sourceFilename) {
    console.warn('[Build Rotation Job List] No CardImage in between record for: ' + cardName);
    continue;
  }

  if (!outputFilename) {
    console.warn('[Build Rotation Job List] No CardImageUpright in between record for: ' + cardName);
    continue;
  }

  const sourcePath = cardDir + '/' + sourceFilename;
  const outputPath = cardDir + '/' + outputFilename;

  // Skip if output already exists (overridable assets pattern)
  if (fs.existsSync(outputPath)) {
    console.warn('[Build Rotation Job List] Skipping existing: ' + outputFilename);
    skipped++;
    continue;
  }

  // Check source image exists
  if (!fs.existsSync(sourcePath)) {
    console.warn('[Build Rotation Job List] Source image missing: ' + sourcePath);
    noSource++;
    continue;
  }

  jobs.push({
    CardName:       cardName,
    SourcePath:     sourcePath,
    OutputPath:     outputPath,
    SourceFilename: sourceFilename,
    OutputFilename: outputFilename,
    FfmpegExe:      params.FfmpegExe
  });
}

if (jobs.length === 0 && skipped === 0 && noSource === 0) {
  throw new Error(
    '[Build Rotation Job List] No jobs created. ' +
    'Check that deck.Cards is populated and card JSONs have between records with CardImage and CardImageUpright fields.'
  );
}

if (jobs.length === 0 && skipped > 0) {
  throw new Error(
    '[Build Rotation Job List] All ' + skipped + ' upright images already exist. ' +
    'Delete CARDIMGUPRIGHT_*_between.png files to regenerate.'
  );
}

if (jobs.length === 0 && noSource > 0) {
  throw new Error(
    '[Build Rotation Job List] No source images found. ' +
    noSource + ' CARDIMG_*_between.png files are missing from the Cards directory.'
  );
}

console.log(
  '[Build Rotation Job List] Created ' + jobs.length + ' jobs' +
  ' (' + skipped + ' already exist, ' + noSource + ' missing source, skipped).'
);
return jobs.map(function(j) { return { json: j }; });

const { execFileSync } = require('child_process');
const fs = require('fs');

const allJobs = $input.all().map(function(i) { return i.json; });
const results = [];
const errors  = [];

if (allJobs.length === 0) {
  throw new Error('[Rotate Between Images] No jobs received.');
}

for (const job of allJobs) {
  try {
    // ffmpeg transpose=2 = 90° counter-clockwise = -90° rotation
    execFileSync(
      job.FfmpegExe,
      [
        '-y',
        '-i', job.SourcePath,
        '-vf', 'transpose=2',
        '-update', '1',
        job.OutputPath
      ],
      { encoding: 'utf8', timeout: 30000 }
    );

    // Verify output was created
    if (fs.existsSync(job.OutputPath)) {
      console.log('[Rotate] OK: ' + job.OutputFilename);
      results.push({
        CardName:       job.CardName,
        SourcePath:     job.SourcePath,
        OutputPath:     job.OutputPath,
        OutputFilename: job.OutputFilename,
        Status:         'OK'
      });
    } else {
      throw new Error('Output file not created');
    }
  } catch (e) {
    const errMsg = ((e.stderr || '') + (e.message || '')).slice(0, 400);
    console.warn('[Rotate] Error for ' + job.CardName + ': ' + errMsg);
    errors.push({
      CardName:       job.CardName,
      SourcePath:     job.SourcePath,
      OutputPath:     job.OutputPath,
      OutputFilename: job.OutputFilename,
      Status:         'Error',
      error:          errMsg
    });
  }
}

if (results.length === 0) {
  throw new Error(
    '[Rotate Between Images] All ' + errors.length + ' jobs failed. First error: ' +
    (errors[0] && errors[0].error)
  );
}

if (errors.length > 0) {
  console.warn(
    '[Rotate Between Images] Completed with ' + errors.length +
    ' errors (' + results.length + ' succeeded).'
  );
}

return [...results, ...errors].map(function(r) { return { json: r }; });

const all    = $input.all().map(function(i) { return i.json; });
const ok     = all.filter(function(j) { return j.Status === 'OK'; });
const failed = all.filter(function(j) { return j.Status === 'Error'; });

console.log(
  '[Report] Between upright images: ' + ok.length + ' succeeded, ' +
  failed.length + ' failed of ' + all.length + ' total.'
);

if (failed.length > 0) {
  console.warn('[Report] Failed cards:');
  failed.forEach(function(f) {
    console.warn('  ' + f.CardName + ': ' + f.error);
  });
}

return [{
  json: {
    succeeded:   ok.length,
    failed:      failed.length,
    total:       all.length,
    failedCards: failed.map(function(f) { return { card: f.CardName, error: f.error }; })
  }
}];
